	public class Symbol : IComparable<Symbol>, IEquatable<Symbol>
	{
		string _ticker = "";
		string _description = "";
		string _equityBeta = "";
		string _sector = "";
		string _industry;
		string _subIndustry;
		string _country;
		string _securitytype;
		string _interval = "";

		string _priceToSalesRatio;
		string _priceToEarningsRatio;
		string _priceToBookRatio;
		string _priceToCashFlow;

		string _group = "";
		int _size1 = 0;
		int _size2 = 0;
		int _size3 = 0;
		DateTime _time1 = new DateTime();
		Dictionary<string, double> _vwap = new Dictionary<string, double>();
		Dictionary<string, double> _beta = new Dictionary<string, double>();
		Dictionary<string, double> _betaTtest = new Dictionary<string, double>();
		Dictionary<string, double> _volatility30D = new Dictionary<string, double>();
		Dictionary<string, double> _dividends = new Dictionary<string, double>();
		Dictionary<string, double> _splits = new Dictionary<string, double>();
		Dictionary<string, double> _marketcap = new Dictionary<string, double>();

		public Symbol(string ticker = "", string description = "", string group = "", string sector = "", int size1 = 0, int size2 = 0, DateTime time1 = new DateTime())
		{
			_ticker = ticker;
			_description = description;
			_group = group;
			_sector = sector;
			_size1 = size1;
			_size2 = size2;
			_time1 = time1;
		}

		public override string ToString()
		{
			string output = _ticker + "\t" + _description + "\t" + _sector + "\t" + _industry + "\t" + _country + "\t" + _securitytype + "\t" + _priceToSalesRatio + "\t" + _priceToEarningsRatio
				+ "\t" + _priceToBookRatio + "\t" + _priceToCashFlow + "\t" + _interval + "\t";

			var count = _vwap.Count;
			output += count + ",";
			_vwap.ToList().ForEach(x => output += x.Key + "," + x.Value + ",");

			return output;
		}
		public void FromString(string input)
		{
			try
			{
				int index = 0;

				string[] fields = input.Split('\t');
				_ticker = fields.Length > index ? fields[index++] : "";
				_description = fields.Length > index ? fields[index++] : "";
				_sector = fields.Length > index ? fields[index++] : "";
				_industry = fields.Length > index ? fields[index++] : "";
				_country = fields.Length > index ? fields[index++] : "";
				_securitytype = fields.Length > index ? fields[index++] : "";
				_priceToSalesRatio = fields.Length > index ? fields[index++] : "";
				_priceToEarningsRatio = fields.Length > index ? fields[index++] : "";
				_priceToBookRatio = fields.Length > index ? fields[index++] : "";
				_priceToCashFlow = fields.Length > index ? fields[index++] : "";
				_interval = fields.Length > index ? fields[index++] : "";

				if (fields.Length > index)
				{
					var vwap = fields[index++];
					var f = vwap.Split(',');
					var count = int.Parse(f[0]);
					for (var ii = 0; ii < count; ii++)
					{
						var idx = 2 * ii + 1;
						var key = f[idx];
						var value = double.Parse(f[idx + 1]);
						_vwap[key] = value;
					}
				}
			}
			catch
			{
			}
		}

		public static char SpreadCharacter
		{
			get { return '|'; }
		}

		public int CompareTo(Symbol other)
		{
			int output = _size1.CompareTo(other._size1);
			if (output == 0) output = _ticker.CompareTo(other._ticker);
			return output;
		}

		public bool Equals(Symbol other)
		{
			return _ticker == other._ticker;
		}

		public override int GetHashCode()
		{
			return _ticker.GetHashCode();
		}

