		private class ReferenceDataRequest : PortfolioRequest
		{
			private List<string> _tickers;
			private string[] _dataFieldNames;
			private bool _current;

			public ReferenceDataRequest(Portfolio portfolio, string ticker, string[] dataFieldNames, bool current)
				: base(portfolio)
			{
				_tickers = new List<string>();
				_tickers.Add(ticker);
				_dataFieldNames = dataFieldNames;
				_current = current;
			}
			public ReferenceDataRequest(Portfolio portfolio, List<string> tickers, string[] dataFieldNames, bool current)
				 : base(portfolio)
			{
				_tickers = tickers;
				_dataFieldNames = dataFieldNames;
				_current = current;
			}
			public List<string> Tickers
			{
				get { return _tickers; }
				set { _tickers = value; }
			}
			public string[] DataFieldNames
			{
				get { return _dataFieldNames; }
				set { _dataFieldNames = value; }
			}
			public bool Current
			{
				get { return _current; }
				set { _current = value; }
			}
		}

