		public Portfolio(int id)
		{
			if (_tickerInfos == null)
			{
				//Debug.WriteLine($"[Portfolio] === LOADING TICKER INFOS ===");

				var filePath = MainView.GetDataFolder() + @"\_StartEndDateSP500.csv";
				//Debug.WriteLine($"[Portfolio] Primary path: {filePath}");
				//Debug.WriteLine($"[Portfolio] Primary file exists: {File.Exists(filePath)}");

				_tickerInfos = ReadTickerInfo(filePath);
				//Debug.WriteLine($"[Portfolio] Loaded from primary: {_tickerInfos?.Count ?? 0} tickers");

				if (_tickerInfos == null || _tickerInfos.Count == 0)
				{
					// Try alternative paths
					var altPaths = new[]
					{
				@"C:\Users\Public\Documents\ATMML\_StartEndDateSP500.csv",
				@"C:\Users\Public\Documents\ATMML\Bloomberg\_StartEndDateSP500.csv"
			};

					foreach (var altPath in altPaths)
					{
						//Debug.WriteLine($"[Portfolio] Trying alternative: {altPath}");
						//Debug.WriteLine($"[Portfolio] Alt file exists: {File.Exists(altPath)}");

						if (File.Exists(altPath))
						{
							_tickerInfos = ReadTickerInfo(altPath);
							//Debug.WriteLine($"[Portfolio] Loaded from alt: {_tickerInfos?.Count ?? 0} tickers");

							if (_tickerInfos?.Count > 0)
							{
								break;
							}
						}
					}
				}

				//Debug.WriteLine($"[Portfolio] === FINAL TICKER COUNT: {_tickerInfos?.Count ?? 0} ===");

				if (_tickerInfos?.Count > 0)
				{
					Debug.WriteLine($"[Portfolio] First 5 tickers:");
					foreach (var t in _tickerInfos.Take(5))
					{
						Debug.WriteLine($"[Portfolio]   - {t.Ticker} | {t.StartDate:yyyy-MM-dd} to {t.EndDate:yyyy-MM-dd}");
					}
				}
				else
				{
					Debug.WriteLine($"[Portfolio] WARNING: No tickers loaded from any path!");
				}
			}

			if (_thread == null)
			{
				_descriptions = new Dictionary<string, string>();
				_sectors = new Dictionary<string, string>();

				List<string> names = MainView.GetPortfolios();
				foreach (string name in names)
				{
					string balanceText = MainView.GetSetting("BalanceV1: " + name);
					string percentText = MainView.GetSetting("BalanceV1: " + name);

					double balance = (balanceText.Length > 0) ? double.Parse(balanceText) : 0;
					double percent = (percentText.Length > 0) ? double.Parse(percentText) : 0;

					if (balance == 0 || double.IsNaN(balance)) balance = getDefaultTradeBalance(name);
					if (percent == 0 || double.IsNaN(percent)) percent = getDefaultTradePercent(name);

					_balances[name] = balance;
					_percents[name] = percent;
				}

				string text1 = MainView.GetSetting("LinkAccounts");
				string text2 = MainView.GetSetting("LinkCharts");

				_linkAccounts = (text1.Length > 0) ? bool.Parse(text1) : false;
				_linkCharts = (text2.Length > 0) ? bool.Parse(text2) : false;

				_runThread = true;
				_thread = new Thread(new ThreadStart(requestSymbolThread));
				_thread.Name = id.ToString();
				_thread.Start();
			}
		}

		public static List<TickerInfo> ReadTickerInfo(string filePath)
		{
			var result = new List<TickerInfo>();

			Debug.WriteLine($"[Portfolio] ReadTickerInfo looking for: {filePath}");
			Debug.WriteLine($"[Portfolio] File exists: {File.Exists(filePath)}");

			if (File.Exists(filePath))
			{
				int lineNumber = 0;
				foreach (var line in File.ReadLines(filePath))
				{
					lineNumber++;

					// Debug first 5 lines
					if (lineNumber <= 5)
					{
						Debug.WriteLine($"[Portfolio] Line {lineNumber}: [{line}]");
					}

					if (string.IsNullOrWhiteSpace(line))
						continue;

					// Try tab-separated first, then comma
					var fields = line.Split('\t');
					if (fields.Length < 5)
					{
						fields = line.Split(',');
					}

					// Debug field count for first 5 lines
					if (lineNumber <= 5)
					{
						Debug.WriteLine($"[Portfolio] Line {lineNumber} has {fields.Length} fields");
						for (int i = 0; i < Math.Min(fields.Length, 5); i++)
						{
							Debug.WriteLine($"[Portfolio]   Field[{i}]: [{fields[i]}]");
						}
					}

					if (fields.Length < 5)
					{
						if (lineNumber <= 5)
							Debug.WriteLine($"[Portfolio] Line {lineNumber} SKIPPED: only {fields.Length} fields");
						continue;
					}

					var ticker = fields[0].Trim();
					var startDateStr = fields[1].Trim();
					var endDateStr = fields[2].Trim();
					var sectorTicker = fields[4].Trim();

					// Skip header if present
					if (ticker.Equals("Ticker", StringComparison.OrdinalIgnoreCase) ||
						ticker.Equals("Symbol", StringComparison.OrdinalIgnoreCase))
					{
						Debug.WriteLine($"[Portfolio] Line {lineNumber} SKIPPED: header row");
						continue;
					}

					// Parse dates - format is M/d/yyyy (e.g., 3/23/2015)
					if (!DateTime.TryParse(startDateStr, CultureInfo.InvariantCulture, DateTimeStyles.None, out var startDate))
					{
						if (!DateTime.TryParseExact(startDateStr, new[] { "M/d/yyyy", "MM/dd/yyyy", "yyyy-MM-dd" },
							CultureInfo.InvariantCulture, DateTimeStyles.None, out startDate))
						{
							if (lineNumber <= 5)
								Debug.WriteLine($"[Portfolio] Line {lineNumber} SKIPPED: Invalid StartDate [{startDateStr}]");
							continue;
						}
					}

					DateTime endDate = DateTime.MaxValue;
					if (!string.IsNullOrWhiteSpace(endDateStr))
					{
						if (!DateTime.TryParse(endDateStr, CultureInfo.InvariantCulture, DateTimeStyles.None, out endDate))
						{
							if (!DateTime.TryParseExact(endDateStr, new[] { "M/d/yyyy", "MM/dd/yyyy", "yyyy-MM-dd" },
								CultureInfo.InvariantCulture, DateTimeStyles.None, out endDate))
							{
								endDate = DateTime.MaxValue;
							}
						}
					}

					result.Add(new TickerInfo
					{
						Ticker = ticker,
						StartDate = startDate,
						EndDate = endDate,
						SectorTicker = sectorTicker
					});

					if (lineNumber <= 5)
						Debug.WriteLine($"[Portfolio] Line {lineNumber} PARSED: {ticker}");
				}

				Debug.WriteLine($"[Portfolio] Total lines read: {lineNumber}");
				Debug.WriteLine($"[Portfolio] Parsed {result.Count} tickers from {filePath}");
			}
			else
			{
				Debug.WriteLine($"[Portfolio] File not found: {filePath}");
			}

			return result;
		}
		public static void SavePortfolioInfo()
		{
			foreach (KeyValuePair<string, double> kvp in _balances)
			{
				MainView.SaveSetting("BalanceV1: " + kvp.Key, kvp.Value.ToString());
			}
			foreach (KeyValuePair<string, double> kvp in _percents)
			{
				MainView.SaveSetting("PercentV1: " + kvp.Key, kvp.Value.ToString());
			}

			MainView.SaveSetting("LinkAccounts", _linkAccounts.ToString());
			MainView.SaveSetting("LinkCharts", _linkCharts.ToString());
		}

		public void Close()
		{
			Clear();
			if (_thread != null)
			{
				_runThread = false;
				_thread.Join(1000);
				_thread = null;
			}
		}
		private void requestSymbolThread()
		{
			int requestsPerSecond = 200; // 4 is smallest

			int sleepMilliseconds = 1000;
			double loopFrequency = 1000.0 / sleepMilliseconds;
			int maxRequestsPerLoop = (int)(requestsPerSecond / loopFrequency + 0.5);

			List<PortfolioRequest> requestList = new List<PortfolioRequest>();

			while (_runThread)
			{
				if (!_blpApiRegistered && DateTime.Now > _blpApiRegisterTime)
				{
					_blpApiRegisterTime = DateTime.Now + new TimeSpan(0, 0, 15);
					registerTerminalConnect();
				}

				lock (_requestList)
				{
					int count1 = Math.Min(_requestList.Count, maxRequestsPerLoop);
					if (count1 > 0)
					{

						for (int ii = 0; ii < count1; ii++)
						{
							requestList.Add(_requestList[ii]);
						}

						for (int ii = 0; ii < count1; ii++)
						{
							_requestList.RemoveAt(0);
						}
					}
				}

				int count2 = requestList.Count;
				if (count2 > 0)
				{
					bool bp = true;
					for (int ii = 0; ii < count2 && _runThread; ii++)
					{
						Portfolio portfolio = requestList[ii].Portfolio;

						SymbolRequest symbolRequest = requestList[ii] as SymbolRequest;
						if (symbolRequest != null)
						{
							//Trace.WriteLine("Portfolio " + symbolRequest.Name + " " + symbolRequest.Type);
							bool ok = portfolio.requestSymbols(symbolRequest);
							if (!ok)
							{
								lock (_requestList)
								{
									_requestList.Add(symbolRequest);
								}
							}
						}
						else
						{
							BetaRequest betaRequest = requestList[ii] as BetaRequest;
							if (betaRequest != null)
							{
								portfolio.requestBeta(betaRequest.Ticker, betaRequest.Date);
							}
							else
							{
								ReferenceDataRequest referenceDataRequest = requestList[ii] as ReferenceDataRequest;
								if (referenceDataRequest != null)
								{
									bool spread = referenceDataRequest.Tickers[0].Contains(Symbol.SpreadCharacter);
									if (spread)
									{
										PortfolioEventArgs eventArgs = new PortfolioEventArgs(PortfolioEventType.ReferenceData, referenceDataRequest.Tickers[0], new Dictionary<string, object>(), 20);
										onPortfolioChanged(eventArgs);
									}
									else
									{
										portfolio.requestReferenceData(referenceDataRequest.Tickers, referenceDataRequest.DataFieldNames, referenceDataRequest.Current);
									}
								}
							}
						}
					}
					requestList.Clear();
				}

				if (_runThread)
				{
					Thread.Sleep(sleepMilliseconds);
				}
			}
		}

