		public void Clear()
		{
			saveBetas();

			lock (_symbols)
			{
				_symbols.Clear();
			}
			lock (_requestList)
			{
				_requestList.Clear();
			}
		}

		private string modifyExchangeCode(string input)
		{
			var output = input;
			var f = input.Split(' ');
			if (f.Length == 3)
			{
				var x = f[1];
				if (x == "UQ" || x == "UW" || x == "UN") output = f[0] + " US " + f[2];
				// else if (x == "??") output = f[0] + " ?? " + f[2];
			}
			return output;
		}

		public static bool isCQGSymbol(string symbol)
		{
			return (symbol.Length > 1 && symbol[1] == '.');
		}

		public List<Symbol> GetSymbols()
		{
			List<Symbol> symbols = new List<Symbol>();
			lock (_symbols)
			{
				symbols.AddRange(_symbols.Values);
			}

			foreach (var symbol in symbols)
			{
				if (!isCQGSymbol(symbol.Ticker))
				{

					// very slow
					if (!symbol.Ticker.Contains(Symbol.SpreadCharacter))
					{
						var data1 = loadData(symbol.Ticker, "DS192", false);
						var description = data1.ContainsKey("Value1") ? data1["Value1"] : "";
						var data2 = loadData(symbol.Ticker, "GICS_SECTOR", false);
						var sector = data2.ContainsKey("Value1") ? data2["Value1"] : "";
						var data3 = loadData(symbol.Ticker, "GICS_INDUSTRY_NAME", false);
						var industry = data3.ContainsKey("Value1") ? data3["Value1"] : "";
						var data4 = loadData(symbol.Ticker, "COUNTRY", false);
						var country = data4.ContainsKey("Value1") ? data4["Value1"] : "";
						var data5 = loadData(symbol.Ticker, "SECURITY_TYP", false);
						var securityType = data5.ContainsKey("Value1") ? data5["Value1"] : "";
						var data6 = loadData(symbol.Ticker, "EQY_WEIGHTED_AVG_PX", true);
						var data7 = loadData(symbol.Ticker, "CUR_MKT_CAP", true);
						var data8 = loadData(symbol.Ticker, "BETA_ADJ_OVERRIDABLE", true);
						var data9 = loadData(symbol.Ticker, "BETA_T_TEST", true);
						var data10 = loadData(symbol.Ticker, "VOLATILITY_30D", true);
						var data11 = loadData(symbol.Ticker, "DV156", true);

						if (symbol.Description.Length == 0) symbol.Description = description;
						symbol.Sector = sector;
						symbol.Industry = industry;
						symbol.Country = country;
						symbol.SecurityType = securityType;
						symbol.VWAP = data6.ToList().ToDictionary(x => x.Key, x => double.Parse(x.Value));
						symbol.Marketcap = data7.ToList().ToDictionary(x => x.Key, x => double.Parse(x.Value));
						symbol.Beta = data8.ToList().ToDictionary(x => x.Key, x => double.Parse(x.Value));
						symbol.BetaTTest = data9.ToList().ToDictionary(x => x.Key, x => double.Parse(x.Value));
						symbol.Volatility30D = data10.ToList().ToDictionary(x => x.Key, x => double.Parse(x.Value));
						symbol.Ticker = modifyExchangeCode(symbol.Ticker);
						symbol.Dividends = data11.ToList().ToDictionary(x => x.Key, x => double.Parse(x.Value));
					}
				}
			}
			return symbols;
		}

		public Dictionary<string, double> GetBeta(string ticker)
