		public void RequestSymbols(string name, PortfolioType type, bool requestExtraInfo)
		{
			//Trace.WriteLine("Portfolio RequestSymbols " + name + " " + type);


			if (name.Length >= 4 && name.Substring(0, 4) == "EQS.")
			{
				type = PortfolioType.EQS;
				name = name.Substring(4);
			}
			else if (name.Length >= 5 && name.Substring(0, 5) == "PRTU.")
			{
				type = PortfolioType.PRTU;
				name = name.Substring(5);
			}
			else if (name.Length >= 7 && name.Substring(0, 7) == "Spread.")
			{
				type = PortfolioType.Spread;
				name = name.Substring(7);
			}

			bool request = true;
			Dictionary<string, Symbol> symbols = null;

			if (type == PortfolioType.Single)
			{
				symbols = new Dictionary<string, Symbol>();
				symbols[name] = new Symbol(name);
				request = false;
			}
			else if (type != PortfolioType.Model)
			{
				symbols = getCustomPorfolio(name);
			}

			//Trace.WriteLine("return from get custom portfolios " + ((symbols == null) ? "null" : symbols.Count.ToString()));
			if (symbols != null && symbols.Count > 0)
			{
				lock (_symbols)
				{
					_symbols = symbols;
				}

				onPortfolioChanged(new PortfolioEventArgs(PortfolioEventType.Symbol));
				request = false;
			}
			else if (type == PortfolioType.Alert)
			{
				request = false;
				try
				{
					Dictionary<string, Symbol> alertSymbols = new Dictionary<string, Symbol>();

					var path = @"alerts\" + name;
					var data = MainView.LoadUserData(path);
					var lines = data.Split('\n');

					foreach (var line in lines)
					{
						if (line.Length > 0)
						{

							var item = AlertItem.FromString(line);
							var ticker = item.Symbol;
							var description = item.Description;
							var size = (item.Side == 0) ? 1 : -1;
							var symbol = new Symbol(ticker, description, "", "", size, size);
							symbol.Interval = item.Interval;
							alertSymbols[ticker] = symbol;
						}
					}
					_symbols = alertSymbols;
					onPortfolioChanged(new PortfolioEventArgs(PortfolioEventType.Symbol));
				}
				catch (Exception x)
				{

				}
			}

			if (request)
			{
				lock (_requestList)
				{
					_requestList.Add(new SymbolRequest(this, name, type, requestExtraInfo));
				}
			}
		}

		public void SetSymbols(List<Symbol> symbols)
		{
			lock (_symbols)
			{
				_symbols.Clear();
				foreach (Symbol symbol in symbols)
				{
					string ticker = symbol.Ticker;
					_symbols[ticker] = symbol;
				}
			}
			requestSymbolInfo(true);   // get vwaps or not
		}

		public int GetSymbolCount()
		{
			return _symbols.Count;
		}

		private bool openSession()
		{
			bool ok = false;
			if ((object)_session != null)
			{
				ok = true;
			}
			else
			{
				try
				{
					SessionOptions sessionOptions = new SessionOptions();
					sessionOptions.ConnectTimeout = 60 * 1000;
					sessionOptions.ServerHost = _host;
					sessionOptions.ServerPort = _port;

					_session = new Session(sessionOptions, new Bloomberglp.Blpapi.EventHandler(processEvent));

					if (_session.Start())
					{
						ok = _session.OpenService("//blp/refdata");
						if (!ok)
						{
							_session.Stop();
							_session = null;
						}
					}
					else
					{
						_session = null;
					}
				}
				catch (Exception)
				{
				}
			}
			return ok;
		}

		private bool requestSymbols(SymbolRequest request)
		{
			Debug.WriteLine($"[Portfolio] === requestSymbols ===");
			Debug.WriteLine($"[Portfolio] Request.Name: {request.Name}");
			Debug.WriteLine($"[Portfolio] Request.Type: {request.Type}");

			bool ok = true;

			_symbolChange = false;

			if (request.Type == PortfolioType.Single)
			{
				lock (_symbols)
				{
					_symbols.Clear();
					string ticker = request.Name;
					Symbol symbol = new Symbol(ticker);
					_symbols[ticker] = symbol;
				}
				onPortfolioChanged(new PortfolioEventArgs(PortfolioEventType.Symbol));
			}
			else if (request.Type == PortfolioType.LIST)
			{
				lock (_symbols)
				{
					_symbols.Clear();
					var tickers = request.Name.Split('\t');
					foreach (var ticker in tickers)
					{
						if (ticker.Length > 0)
						{
							Symbol symbol = new Symbol(ticker);
							_symbols[ticker] = symbol;
						}
					}
				}
				onPortfolioChanged(new PortfolioEventArgs(PortfolioEventType.Symbol));
			}

			else if (request.Type == PortfolioType.Spread)
			{
				lock (_symbols)
				{
					string[] names = request.Name.Split('.');
					string ticker = names[0];

					List<string> tickers1 = new List<string>();
					if (ticker != "FINANCIAL RISK")
					{
						tickers1.Add(ticker);
					}

					_symbols.Clear();

					if (names.Length > 1)
					{
						string portfolioName = names[1];
						Dictionary<string, Symbol> symbols2 = getCustomPorfolio(portfolioName);
						if (symbols2 != null)
						{
							foreach (string ticker1 in tickers1)
							{
								foreach (string ticker2 in symbols2.Keys)
								{
									if (ticker1 != ticker2)
									{
										string spreadTicker = ticker1 + " - " + ticker2;
										Symbol symbol = new Symbol(spreadTicker);
										_symbols[spreadTicker] = symbol;
									}
								}
							}
							requestSymbolInfo(true);
						}
					}
				}
				onPortfolioChanged(new PortfolioEventArgs(PortfolioEventType.Symbol));
			}
			else if (request.Type == PortfolioType.Model)
			{
				var data = getModelPortfolios(request.Name);

				List<Symbol> symbols = new List<Symbol>();

				List<string> dates = data.Keys.ToList();
				if (dates.Count > 0)
				{
					dates.Sort();

					dates.ForEach(date =>
					{
						foreach (var kvp2 in data[date])
						{
							var ticker = kvp2.Key;
							var direction = int.Parse(kvp2.Value);
							if (atm.isYieldTicker(ticker)) direction = -direction;
							if (direction != 0)
							{
								var symbol = new Symbol(ticker, "", "", "", direction, 0, DateTime.ParseExact(date, "yyyyMMdd", null));

								lock (_symbols)
								{
									_symbols[symbol.Ticker] = symbol;
								}
							}
						}
					});
				}

				onPortfolioChanged(new PortfolioEventArgs(PortfolioEventType.Symbol));
			}
			else if (request.Type == PortfolioType.Worksheet)
			{
				//if (_worksheets.ContainsKey(request.Name))
				//{
				//    var tickers = _worksheets[request.Name].GetSecurities().ToList();
				//    tickers.ForEach(x => _symbols[x] = new Symbol(x));
				//}
				//onPortfolioChanged(new PortfolioEventArgs(PortfolioEventType.Symbol));
			}
			else
			{
				Dictionary<string, Symbol> symbols = getCustomPorfolio(request.Name);
				if (symbols != null)
				{
					lock (_symbols)
					{
						_symbols = symbols;
					}
					onPortfolioChanged(new PortfolioEventArgs(PortfolioEventType.Symbol));
				}
				else
				{
					_requestExtraInfo = request.RequestSymbolInfo;
					Debug.WriteLine($"[Portfolio] Calling requestBloombergSymbols for: {request.Name}");
					ok = requestBloombergSymbols(request.Name, request.Type);
				}
			}
			return ok;
		}

