		private Dictionary<string, Dictionary<string, string>> getModelPortfolios(string modelName, bool rebalance = false)
		{
			var output = new Dictionary<string, Dictionary<string, string>>();
			var trades1 = GetTrades(modelName);
			if (trades1.Count > 0)
			{
				var lastExitDate = trades1.Select(x => x.CloseDateTime).Max();
				var trades2 = trades1.Where(x => x.CloseDateTime == default || x.CloseDateTime == lastExitDate).ToList();
				foreach (Trade trade in trades2)
				{
					var ticker = trade.Ticker;
					var date = trade.CloseDateTime.ToString("yyyyMMdd");
					var direction = trade.Direction;
					var exitPrice = trade.ExitPrice;

					if (!double.IsNaN(exitPrice))
					{
						direction = (direction > 0) ? 3 : -3;
					}

					if (!output.ContainsKey(date))
					{
						output[date] = new Dictionary<string, string>();
					}
					output[date][ticker] = direction.ToString();
				}
			}
			return output;
		}

		public Dictionary<string, double> GetModelPortfolioAllocations(string modelName)
		{
			var output = new Dictionary<string, double>();
			string path = @"portfolios\" + modelName;
			var data = MainView.LoadUserData(path);
			var lines = data.Split('\n');
			int latestDate = 0;
			foreach (var line in lines)
			{
				if (line.Length > 0)
				{
					string[] fields = line.Split(',');
					int date = int.Parse(fields[0]);
					if (date > latestDate)
					{
						latestDate = date;
					}
				}
			}

			double totalInvestment = 0;
			var investments = new Dictionary<string, double>();

			foreach (var line in lines)
			{
				if (line.Length > 0)
				{
					string[] fields = line.Split(',');
					if (fields.Length > 2)
					{
						int date = int.Parse(fields[0]);
						if (date == latestDate)
						{
							string ticker = fields[1];
							int direction = int.Parse(fields[2]);
							double investment = double.Parse((fields.Length > 3) ? fields[3] : "1");

							investments[ticker] = Math.Sign(direction) * investment;
							totalInvestment += investment;
						}
					}
				}
			}

			foreach (var kvp in investments)
			{
				output[kvp.Key] = kvp.Value / totalInvestment;
				//Trace.WriteLine(kvp.Key + " " + output[kvp.Key]);
			}

			return output;
		}

		private List<Symbol> getModelSymbols(string date, Dictionary<string, Dictionary<string, string>> data)
		{
			var output = new List<Symbol>();

			if (data.Count > 0)
			{
				var dates = data.Keys.ToList();
				dates.Sort();

				int dateIndex = dates.Count - 1;
				for (int ii = dates.Count - 1; ii >= 0; ii--)
				{
					dateIndex = ii;
					if (dates[ii].CompareTo(date) <= 0)
					{
						break;
					}
				}

				string key = dates[dateIndex];
				foreach (var kvp1 in data[key])
				{
					var ticker = kvp1.Key;
					string entryDate = key;
					var direction = kvp1.Value;

					for (int ii = dateIndex - 1; ii >= 0; ii--)
					{
						if (data[dates[ii]].ContainsKey(ticker) && data[dates[ii]][ticker] == direction)
						{
							entryDate = dates[ii];
						}
						else
						{
							break;
						}
					}

					var symbol = new Symbol(ticker, "", "", "", int.Parse(direction), 0, DateTime.ParseExact(entryDate, "yyyyMMdd", null));

					output.Add(symbol);
				}
			}
			return output;
		}

		public List<Trade> GetTrades(string name, string symbol = "", DateTime date = default(DateTime), bool all = false)
		{
			var output = new List<Trade>();

			var portfolioNames = name.Split(',');

			foreach (var portfolioName in portfolioNames)
			{
				if (portfolioName == "CMR" || portfolioName == "SQ PT" || portfolioName == "TMSG")
				{
					output.AddRange(Trade.Manager.getTrades(portfolioName).Where(x => x.Direction != 0 && (all || x.IsOpen())).ToList());
				}
				else
				{
					string path = @"portfolios\trades\" + portfolioName;
					var data = MainView.LoadUserData(path);
					var lines = data.Split('\n');
					foreach (var line in lines)
					{
						if (line.Length > 0)
						{
							var trade = new Trade();
							trade.Deserialize(line);
							//if (all || trade.IsOpen())
							{
								output.Add(trade);
							}
						}
					}
				}
			}

			if (symbol.Length > 0)
			{
				output = output.Where(x => x.Ticker == symbol).ToList();
			}
			if (date != default(DateTime))
			{
				output = all ? output.Where(x => x.OpenDateTime <= date).ToList() : output.Where(x => x.OpenDateTime <= date && (x.IsOpen() || date < x.CloseDateTime)).ToList();
			}

			return output;
		}

