		public double GetTradeBalance(string name)
		{
			double balance = 0;
			if (_balances.ContainsKey(name))
			{
				balance = _balances[name];
			}
			else
			{
				balance = getDefaultTradeBalance(name);
			}
			return balance;
		}

		public double GetTradePercent(string name)
		{
			double percent = 0;
			if (_percents.ContainsKey(name))
			{
				percent = _percents[name];
			}
			else
			{
				percent = getDefaultTradePercent(name);
			}
			return percent;
		}

		private double getDefaultTradePercent(string name)
		{
			double percent = 1;

			if (String.Compare(name, "US 100", true) == 0)
			{
				percent = 1;
			}
			else if (String.Compare(name, "US 100 H", true) == 0)
			{
				percent = 2;
			}
			else if (String.Compare(name, "SINGLE CTY ETF", true) == 0)
			{
				percent = 2;
			}
			return percent;
		}

		private double getDefaultTradeBalance(string name)
		{
			double balance = 1000000;
			return balance;
		}

