		public string GetTradeNetwork(string name, TradeHorizon horizon = TradeHorizon.MidTerm, string symbol = "") // ASSET OR PORTFOLIO
		{
			string network = "";
			if (String.Compare(name, "US 500", true) == 0)
			{
				EquityInfo[] infos = Portfolio.GetEquityInfos();
				foreach (EquityInfo info in infos)
				{
					if (symbol == info.Symbol)
					{
						string sector = info.Sector.Replace("S5", "");
						network = "CMR " + sector + " US Lg Cap";
						if (horizon == TradeHorizon.ShortTerm) network += " ST";
						else if (horizon == TradeHorizon.MidTerm) network += " MT";
						else if (horizon == TradeHorizon.LongTerm) network += " LT";

						break;
					}
				}
			}
			else if (String.Compare(name, "US 100 H", true) == 0)
			{
				network = "CMR US $ N-N"; // "CMR US $ N-N";
			}
			else if (String.Compare(name, "SINGLE CTY ETF", true) == 0)
			{
				network = "CMR Single Country ETF"; // "TestR";  //"CMR Global Macro ETF";
			}
			else if (String.Compare(name, "GLOBAL INDICES", true) == 0)
			{
				network = "CMR GLOBAL INDICES";
			}
			else if (name.Length > 0 && name[0] == 'U' && name.Contains('-'))
			{
				network = name + " Client";
			}
			else
			{
				network = name;
			}

			return network;
		}

