		public List<string> GetTradePortfolios(string symbol, bool combineOutRightAndHedged)
		{
			List<string> portfolios = new List<string>();
			Dictionary<string, Symbol> symbols = get_US_100();
			if (symbols.ContainsKey(symbol)) portfolios.Add("US 100");

			symbols = get_US_100_H();

			if (!combineOutRightAndHedged)
			{
				if (symbols.ContainsKey(symbol)) portfolios.Add("US 100 H");
			}
			else
			{
				foreach (string spread in symbols.Keys)
				{
					string[] fields = spread.Split(Symbol.SpreadCharacter);
					string ticker = fields[0].Trim();
					if (symbol == ticker)
					{
						portfolios.Add("US 100 H");
						break;
					}
				}
			}

			symbols = get_Single_Cty_ETF();
			if (symbols.ContainsKey(symbol)) portfolios.Add("SINGLE CTY ETF");

			symbols = getMuniStateName();
			if (symbols.ContainsKey(symbol)) portfolios.Add("STATE INDICES");

			return portfolios;
		}

		public string GetTradeHedge(string portfolio, string symbol)
		{
			string hedge = "";

			if (portfolio == "US 100 H")
			{
				Dictionary<string, Symbol> symbols = get_US_100_H();
				foreach (string spread in symbols.Keys)
				{
					string[] fields = spread.Split(Symbol.SpreadCharacter);
					string ticker = fields[0].Trim();
					if (symbol == ticker)
					{
						hedge = fields[1].Trim();
						break;
					}
				}
			}

			return hedge;
		}

		private Dictionary<string, Symbol> getCustomPorfolio(string name)
		{
			Dictionary<string, Symbol> symbols = null;

			Dictionary<string, Symbol> cmrSymbols = null;
			if (Trade.Manager.Portfolios.TryGetValue(name, out cmrSymbols))
			{
				symbols = new Dictionary<string, Symbol>();
				foreach (KeyValuePair<string, Symbol> kvp in cmrSymbols)
				{
					symbols[kvp.Key] = new Symbol(kvp.Value.Ticker);
				}
			}

			var cqgPorts = new string[] { "CME", "CBOT", "COMEX", "NYMEX", "BMF", "DevX" };
			var items = name.Split(new char[] { ' ' }, 2);
			if (items.Length == 2 && cqgPorts.Contains(items[0]))
			{
				symbols = getSymbols(items[0], items[1]);
			}

			if (String.Compare(name, "OEXNDX", true) == 0)
			{
				symbols = get_OEXNDX();
			}
			else if (String.Compare(name, "SP", true) == 0)
			{
				symbols = get_SPX();
			}
			else if (String.Compare(name, "SPXL1", true) == 0)
			{
				symbols = get_SPXL1();
			}
			else if (String.Compare(name, "SPXL2", true) == 0)
			{
				symbols = get_SPXL2();
			}
			else if (String.Compare(name, "SPXL3", true) == 0)
			{
				symbols = get_SPXL3();
			}
