				foreach (KeyValuePair<string, Symbol> kvp in Trade.Manager.getOpenTradeSymbolsForNetwork("SQPT", 0))
				{
					string[] fields = kvp.Value.Ticker.Split(' ');
					if (!Char.IsDigit(fields[0][0]) && !(fields.Length > 1 && (fields[1] == "US" || fields[1] == "AT")))
					{
						symbols[kvp.Key] = kvp.Value;
						kvp.Value.Description = getDescription(kvp.Key);
					}
				}
			}
			else if (String.Compare(name, "US 500", true) == 0)
			{
				symbols = get_US_500();
			}
