		public string GetCountrySymbol(string country, string asset)
		{
			string symbol = "";
			foreach (CountryInfo countryInfo in _countryInfos)
			{
				if (countryInfo.Name == country && countryInfo.Type == asset)
				{
					symbol = countryInfo.Symbol;
					break;
				}
			}
			return symbol;
		}

		public string getSectorCode(string symbol)
		{
			string sector = "";
			lock (_sectors)
			{
				string text = "";
				if (_sectors.TryGetValue(symbol, out text))
				{
					sector = text;
				}
			}
			return sector;
		}

		public string getSectorSymbol(int input)
		{
			string output = "";
			if (input == 25) output = "XLY US Equity";
			else if (input == 30) output = "XLP US Equity";
			else if (input == 10) output = "XLE US Equity";
			else if (input == 40) output = "XLF US Equity";
			else if (input == 35) output = "XLV US Equity";
			else if (input == 20) output = "XLI US Equity";
			else if (input == 45) output = "XLK US Equity";
			else if (input == 15) output = "XLB US Equity";
			else if (input == 50) output = "XLK US Equity";
			else if (input == 55) output = "XLU US Equity";
			else if (input == 60) output = "XLRE US Equity";
			return output;
		}

