		private string getDescription(string symbol)
		{
			string description = "";

			if (isCQGSymbol(symbol))
			{
				description = GetCQGSymbolDescription(symbol);
			}
			else
			{

				lock (_descriptions)
				{
					string text = "";
					if (_descriptions.TryGetValue(symbol, out text))
					{
						description = text;
					}
				}

				if (description.Length == 0)
				{
					foreach (EquityInfo info in _equityTradeables)
					{
						if (info.Symbol == symbol)
						{
							description = info.Label;
							break;
						}
					}
				}
			}

			return description;
		}

		public string GetDescription(string symbol)
		{
			return getDescription(symbol);
		}

		private Dictionary<string, Symbol> getCountrySymbols(string type)
		{
			Dictionary<string, Symbol> symbols = new Dictionary<string, Symbol>();
			foreach (CountryInfo countryInfo in _countryInfos)
			{
				if (countryInfo.Type == type)
				{
					symbols[countryInfo.Symbol] = new Symbol(countryInfo.Symbol);
				}
			}
			return symbols;
		}

		public static bool IsBuiltInPortfolio(string name)
		{
			bool yes = false;
			List<string> names = Portfolio.GetBuiltInPortfolios(true);
			//names.AddRange(Portfolio.GetPCMPortfolios(true));
			names.AddRange(Portfolio.GetSQPTPortfolios(true));
			foreach (string name1 in names)
			{
				if (name == name1)
				{
					yes = true;
					break;
				}
			}
			return yes;
		}

