		static string GetCQGSymbolDescription(string ticker)
		{
			var output = "";
			ticker += "::";
			var tickerLength = ticker.Length;
			var cqgPortfolios = new string[][]
			{   CQG_CBOT_FINANCIALS,
				CQG_CME_FX,
				CQG_CME_STOCK_INDEX,
				CQG_COMEX_METALS,
				CQG_ICE_SOFTS,
				CQG_NYMEX_ENERGY,
				CQG_NYMEX_METALS,
				CQG_STOCKS_NYSE_75,
				CQG_STOCKS_NASDAQ_100,
			};
			var count1 = cqgPortfolios.Length;
			for (var ii = 0; ii < count1; ii++)
			{
				var count2 = cqgPortfolios[ii].Length;
				for (var jj = 0; jj < count2; jj++)
				{
					var other = cqgPortfolios[ii][jj];
					if (other.Length > tickerLength && other.Substring(0, ticker.Length) == ticker)
					{
						output = other.Substring(tickerLength);
						break;
					}
				}
			}
			return output;
		}

