		static Dictionary<string, Symbol> getSymbols(string exchange, string type)
		{
			var output = new Dictionary<string, Symbol>();

			string[] exchangeSymbols = null;
			if (exchange == "CBOT") exchangeSymbols = CQG_CBOT;
			else if (exchange == "CME") exchangeSymbols = CQG_CME;
			else if (exchange == "COMEX") exchangeSymbols = CQG_COMEX;
			else if (exchange == "NYMEX") exchangeSymbols = CQG_NYMEX;
			else if (exchange == "BMF") exchangeSymbols = CQG_BMF;
			//else if (exchange == "DevX") exchangeSymbols = CQG_DevX;

			if (exchangeSymbols != null)
			{
				foreach (var text in exchangeSymbols)
				{
					var items = text.Split(new[] { "::" }, StringSplitOptions.None);
					if (items.Length >= 3 && items[2] == type)
					{
						Symbol symbol = new Symbol(items[0]);
						symbol.Sector = "";
						symbol.Description = items[1];
						output[items[0]] = symbol;
					}
				}
			}
			return output;
		}

