		public static string getGlobalIndCountryName(string symbol)
		{
			string name = "";
			foreach (string text in Single_Cty_ETF)
			{
				string[] fields = text.Split(':');
				if (fields[0] == symbol && fields.Length > 2)
				{
					name = fields[2];
					break;
				}
			}
			if (name.Length == 0)
			{
				name = symbol;
			}
			return name;
		}
