		public static bool IsCommoditySymbol(string ticker)
		{
			bool yes = false;
			foreach (string symbol in GlobalMacCommodities)
			{
				string[] fields = symbol.Split(':');
				if (ticker == fields[0])
				{
					yes = true;
					break;
				}
			}
			return yes;
		}

		static string[] GlobalMacCommodities =
		{
            //"IAU US Equity: :Gold",	
            //"SLV US Equity: :Silver",
            //"USO US Equity: :Crude",	
            //"UNG US Equity: :Nat Gas",	
        };

		public List<Symbol> GetSymbols(string portfolioName)
		{
			List<Symbol> symbols = new List<Symbol>();

			string[] portfolio = null;

			Dictionary<string, Symbol> dataBaseSymbols;
			if (Trade.Manager.Portfolios.TryGetValue(portfolioName, out dataBaseSymbols))
			{
				symbols = new List<Symbol>(dataBaseSymbols.Values.ToArray());
				return symbols;
			}
			else if (portfolioName == "US STOCKS")
			{
				portfolio = US_500;
			}
			else if (portfolioName == "FIN SPREADS")
			{
				portfolio = Trade.Manager.GetSpreadPositionSymbols().ToArray();
			}
			else if (portfolioName == "US 100 SPREADS")
			{
				//portfolio = US100SPREADS;
			}
			else if (portfolioName == "US 500 SPREADS")
			{
				//portfolio = US500SPREADS;
			}

			if (portfolio != null)
			{
				foreach (string text in portfolio)
				{
					string[] field = text.Split(':');
					string ticker = field[0];
					string sector = (field.Length > 1) ? field[1] : "";
					string name = (field.Length > 2) ? field[2] : "";
					Symbol symbol = new Symbol(ticker);
					symbol.Sector = sector;
					symbol.Description = name;
					symbols.Add(symbol);
				}
			}

			foreach (var symbol in symbols) symbol.Ticker = symbol.Ticker;

			return symbols;
		}

