		private Dictionary<string, Symbol> get_TradeablebyGroup()
		{
			Dictionary<string, Symbol> output = new Dictionary<string, Symbol>();
			foreach (EquityInfo info in _equityTradeables)
			{
				output[info.Symbol] = new Symbol(info.Symbol, info.Label);  // add spacing in position.cs
			}
			return output;
		}

		private Dictionary<string, Symbol> get_TradeableAtoZ()
		{
			Dictionary<string, Symbol> output = new Dictionary<string, Symbol>();

			List<EquityInfo> tradable1 = new List<EquityInfo>(_equityTradeables);
			List<EquityInfo> tradable2 = tradable1.OrderBy(o => o.Symbol).ToList();

			foreach (EquityInfo info in tradable2)
			{
				if (!info.Symbol.Contains(" Index"))
				{
					output[info.Symbol] = new Symbol(info.Symbol, info.Label);   // only US Equity - no Index
				}
			}
			return output;
		}

