		private Dictionary<string, Symbol> get_TradeablebySector()
		{
			Dictionary<string, Symbol> output = new Dictionary<string, Symbol>();

			List<EquityInfo> tradable1 = new List<EquityInfo>(_equityTradeables);
			List<EquityInfo> tradable2 = tradable1.OrderBy(o => o.Sector).ToList();

			string sector = "";
			foreach (EquityInfo info in tradable2)
			{
				if (info.Sector != sector)
				{
					sector = info.Sector;
					string symbol = sector + " Index";
					output[symbol] = new Symbol(symbol, sector);  //make like sp 500  Sector then Group then Group Stks
				}
				output[info.Symbol] = new Symbol(info.Symbol, info.Label);  //make like sp 500  Sector then Group then Group Stks
			}
			return output;
		}

		private Dictionary<string, Symbol> get_TradeableSectorStocks(string sector)
		{
			Dictionary<string, Symbol> output = new Dictionary<string, Symbol>();

			List<EquityInfo> tradable1 = new List<EquityInfo>(_equityTradeables);

			foreach (EquityInfo info in tradable1)
			{
				if (info.Sector == sector)
				{
					string symbol = info.Symbol;
					output[symbol] = new Symbol(symbol, info.Label);  //make like sp 500  Sector then Group then Group Stks
				}
			}
			return output;
		}

