		private Dictionary<string, Symbol> getSymbols(string[] portfolio)
		{
			Dictionary<string, Symbol> symbols = new Dictionary<string, Symbol>();
			foreach (string text in portfolio)
			{
				string[] field = text.Split(':');
				string ticker = field[0];
				string sector = (field.Length > 1) ? field[1] : "";
				string description = (field.Length > 2) ? field[2] : "";
				Symbol symbol = new Symbol(ticker);
				symbol.Sector = sector;
				symbol.Description = description;
				symbols[ticker] = symbol;
			}
			return symbols;
		}



		private Dictionary<string, Symbol> get_FinSpreads()
		{
			Dictionary<string, Symbol> symbols = new Dictionary<string, Symbol>();
			List<string> spreadSymbols = Trade.Manager.GetSpreadPositionSymbols();
			foreach (string symbol in spreadSymbols)
			{
				string[] fields = symbol.Split(';');
				string ticker = fields[0];
				string description = (fields.Length > 1) ? fields[1] : "";
				symbols[ticker] = new Symbol(ticker);
				symbols[ticker].Description = description;
			}
			return symbols;
		}

		private bool requestBloombergSymbols(string name, PortfolioType type)
		{
			bool ok = false;

			if (openSession())
			{
				try
				{
					if (type == PortfolioType.EQS)
					{
						ok = sendEqsDataRequest(name);
					}
					else if (type == PortfolioType.Index)
					{
						ok = sendIndexDataRequest(name);
					}
					else if (type == PortfolioType.PRTU)
					{
						ok = sendPrtuDataRequest(name);
					}
					else if (type == PortfolioType.Peers)
					{
						ok = sendPeersDataRequest(name);
					}
				}
				catch (InvalidRequestException ex)
				{
					Debug.WriteLine($"[Portfolio] Bloomberg InvalidRequestException for {name}: {ex.Message}");
				}
				catch (Exception ex)
				{
					Debug.WriteLine($"[Portfolio] Bloomberg exception for {name}: {ex.Message}");
				}
			}
			else
			{
				Debug.WriteLine($"[Portfolio] Bloomberg session not available, using local fallback for {name}");

				// Session failed to open - use local fallback for Index type
				if (type == PortfolioType.Index)
				{
					ok = loadIndexMembersFromLocal(name);
				}
			}

			return ok;
		}

		private static readonly string LocalDataPath = @"C:\Users\Public\Documents\ATMML\Bloomberg";

		/// <summary>
		/// Load reference data from local files when Bloomberg is unavailable
		/// </summary>
		private Dictionary<string, object> LoadReferenceDataFromLocal(string ticker, string[] dataFieldNames)
		{
			var data = new Dictionary<string, object>();

			try
			{
				// Handle special characters in ticker names (BRK/B -> BRK-B)
				var folderTicker = ticker.Replace("/", "-");
				var folderPath = Path.Combine(LocalDataPath, folderTicker);

				// Try original name if modified version doesn't exist
				if (!Directory.Exists(folderPath))
				{
					folderPath = Path.Combine(LocalDataPath, ticker);
				}

				if (!Directory.Exists(folderPath))
				{
					Debug.WriteLine($"[Portfolio] Local folder not found for {ticker}, using defaults");

					// Provide default values so we don't block
					foreach (var field in dataFieldNames)
					{
						if (field == "REL_INDEX")
						{
							data[field] = "SPX";  // Default relative index
						}
						else if (field == "EQY_BETA" || field.Contains("BETA"))
						{
							data[field] = 1.0;  // Default beta
						}
					}
					return data;
				}

				foreach (var field in dataFieldNames)
				{
					// Try Current value first, then All
					var currentFile = Path.Combine(folderPath, $"{field}_Current.csv");
					var allFile = Path.Combine(folderPath, $"{field}_All.csv");

					string filePath = null;
					if (File.Exists(currentFile))
						filePath = currentFile;
					else if (File.Exists(allFile))
						filePath = allFile;

					if (filePath != null)
					{
						var content = File.ReadAllText(filePath).Trim();

						// Try to parse as number, otherwise keep as string
						if (double.TryParse(content, NumberStyles.Any, CultureInfo.InvariantCulture, out double numValue))
						{
							data[field] = numValue;
						}
						else
						{
							data[field] = content;
						}

						//Debug.WriteLine($"[Portfolio] Loaded {field} for {ticker}: {content}");
					}
					else
					{
						// Provide default if file not found
						if (field == "REL_INDEX")
						{
							data[field] = "SPX";
							//Debug.WriteLine($"[Portfolio] Using default REL_INDEX for {ticker}: SPX");
						}
					}
				}
			}
			catch (Exception ex)
			{
				Debug.WriteLine($"[Portfolio] Error loading local reference data for {ticker}: {ex.Message}");
			}

			return data;
		}
		public void RequestReferenceData(string ticker, string[] dataFieldNames, bool current = false)
		{
			bool spread = ticker.Contains(Symbol.SpreadCharacter);
			if (spread && dataFieldNames.Length == 1 && dataFieldNames[0] == "REL_INDEX")
			{
				var data = new Dictionary<string, object>();
				data["REL_INDEX"] = "SPX";
				PortfolioEventArgs eventArgs = new PortfolioEventArgs(PortfolioEventType.ReferenceData, ticker, data, 4);
				onPortfolioChanged(eventArgs);
			}
			else
			{
				// Try local data first
				var localData = LoadReferenceDataFromLocal(ticker, dataFieldNames);

				if (localData.Count > 0)
				{
					//Debug.WriteLine($"[Portfolio] Using local reference data for {ticker}: {localData.Count} fields");
					PortfolioEventArgs eventArgs = new PortfolioEventArgs(PortfolioEventType.ReferenceData, ticker, localData, 4);
					onPortfolioChanged(eventArgs);
				}
				else
				{
					// Fall back to Bloomberg
					//Debug.WriteLine($"[Portfolio] Requesting reference data from Bloomberg for {ticker}");
					lock (_requestList)
					{
						_requestList.Add(new ReferenceDataRequest(this, ticker, dataFieldNames, current));
					}
				}
			}
		}
		public void RequestReferenceData(List<string> tickers, string[] dataFieldNames, bool current = false)
		{
			lock (_requestList)
			{
				_requestList.Add(new ReferenceDataRequest(this, tickers, dataFieldNames, current));
			}
		}

		public void RequestBetas(string ticker)
		{
			lock (_requestList)
			{
				_requestList.Add(new BetaRequest(this, ticker, DateTime.Now));
			}
		}

		public void RequestBetas(Dictionary<string, List<DateTime>> request)
		{
			if (_loadBetas)
			{
				_loadBetas = false;
				loadBetas();
			}

			foreach (KeyValuePair<string, List<DateTime>> kvp in request)
			{
				string ticker = kvp.Key;
				foreach (DateTime date in kvp.Value)
				{
					string dateKey = date.ToString("yyyy-MM-dd");
					string key = ticker + dateKey;

					string beta = "";
					if (_betas.TryGetValue(key, out beta))
					{
						bool sendNotification = false;
						lock (_symbols)
						{
							if (_symbols.ContainsKey(ticker))
							{
								Symbol symbol = _symbols[ticker];
								symbol.Beta[dateKey] = double.Parse(beta);
								sendNotification = true;
							}
						}
						if (sendNotification)
						{
							onPortfolioChanged(new PortfolioEventArgs(PortfolioEventType.Beta));
						}
					}
					else
					{
						lock (_requestList)
						{
							_requestList.Add(new BetaRequest(this, ticker, date));
						}
					}
				}
			}
		}

		public void saveBetas()
		{
			lock (_symbols)
			{
				if (_betaChange)
				{
					_betaChange = false;

					try
					{
						Dictionary<string, string> betas = new Dictionary<string, string>();

						string text1 = MainView.GetSetting("Betas");
						if (text1 != null)
						{
							string[] items = text1.Split(';');
							for (int ii = 0; ii < items.Length; ii++)
							{
								string[] field = items[ii].Split(':');
								if (field.Length >= 2)
								{
									betas[field[0]] = field[1];
								}
							}
						}

						foreach (Symbol symbol in _symbols.Values)
						{
							string ticker = symbol.Ticker;
							foreach (KeyValuePair<string, double> kvp in symbol.Beta)
							{
								string date = kvp.Key;
								double value = kvp.Value;
								string key = ticker + date;
								betas[key] = value.ToString();
							}
						}

						StringBuilder stringBuilder = new StringBuilder();
						foreach (KeyValuePair<string, string> kvp in betas)
						{
							stringBuilder.Append(kvp.Key + ":" + kvp.Value + ";");
						}

						MainView.SaveSetting("Betas", stringBuilder.ToString());
					}
					catch (Exception)
					{
					}
				}
			}
		}

		public void loadBetas()
		{
			try
			{
				_betas.Clear();
				string text1 = MainView.GetSetting("Betas");
				if (text1 != null)
				{
					string[] items = text1.Split(';');
					Dictionary<string, string> betas = new Dictionary<string, string>();
					for (int ii = 0; ii < items.Length; ii++)
					{
						string[] field = items[ii].Split(':');
						if (field.Length >= 2)
						{
							_betas[field[0]] = field[1];
						}
					}
				}
			}
			catch (Exception)
			{
				//MessageBox.Show("Load betas failed");
			}
		}

