		public bool RequestFundamentalReportDates(List<string> tickers, int startYear)
		{
			bool ok = openSession();

			if (ok)
			{
				try
				{
					Service refDataService = _session.GetService("//blp/refdata");

					var date1 = startYear + "0101";
					var date2 = DateTime.Now.ToString("yyyyMMdd");

					Request request = refDataService.CreateRequest("HistoricalDataRequest");
					Element securities = request.GetElement("securities");
					foreach (var ticker in tickers)
					{
						securities.AppendValue(ticker);
					}

					Element fields = request.GetElement("fields");
					fields.AppendValue("ANNOUNCEMENT_DT");  //DS957

					request.Set("startDate", date1);
					request.Set("endDate", date2);

					var key = "RequestFundamentalReportDates ";
					_session.SendRequest(request, new CorrelationID(key));
				}

				catch (Exception)
				{
					ok = false;
				}
			}
			return ok;
		}

		int _count = 0;
		private void requestHistoricalReferenceData(List<string> tickers, string[] dataFieldNames)
		{
			bool ok = openSession();

			if (ok)
			{
				try
				{
					foreach (var ticker in tickers)
					{
						var requests = new Dictionary<DateTime, List<string>>();
						//foreach(var name in dataFieldNames)
						//{
						//    DateTime time = getStartDate(ticker, name);
						//    if (!requests.ContainsKey(time))
						//    {                
						//        requests[time] = new List<string>();
						//    }
						//    requests[time].Add(name);
						//}

						bool useOldTime = false;

						DateTime minTime = DateTime.MaxValue;
						foreach (var name in dataFieldNames)
						{
							DateTime time = getStartDate(ticker, name);

							if (time.Year < 2010)
							{
								useOldTime = true;
								//System.Diagnostics.Debug.WriteLine(ticker + " " + name + " " + time.ToString("yyyyMMdd") + " " + _count);
							}

							if (time < minTime) minTime = time;
						}

						requests[minTime] = dataFieldNames.ToList();


						foreach (var kvp in requests)
						{
							DateTime startTime = kvp.Key;
							string[] fieldNames = kvp.Value.ToArray();

							Service refDataService = _session.GetService("//blp/refdata");
							Request request = refDataService.CreateRequest("HistoricalDataRequest");
							Element securities = request.GetElement("securities");
							securities.AppendValue(ticker);

							// todo - add interval and start and end dates to request
							var time1 = startTime;
							var time2 = DateTime.Now + new TimeSpan(365, 0, 0, 0);
							var timeText1 = time1.ToString("yyyyMMdd");
							var timeText2 = time2.ToString("yyyyMMdd");

							request.Set("periodicitySelection", "DAILY");
							request.Set("startDate", timeText1);
							request.Set("endDate", timeText2);

							Element overrides = request["overrides"];
							Element override1 = overrides.AppendElement();
							override1.SetElement("fieldId", "DS215");
							override1.SetElement("value", "USD");

							Element override2 = overrides.AppendElement();
							override2.SetElement("fieldId", "BEST_DATA_SOURCE_OVERRIDE");
							override2.SetElement("value", "BST");
							Element override3 = overrides.AppendElement();
							override3.SetElement("fieldId", "BEST_CONSOLIDATED_OVERRIDE");
							override3.SetElement("value", "C");
							Element override4 = overrides.AppendElement();
							override4.SetElement("fieldId", "BEST_FPERIOD_OVERRIDE");
							override4.SetElement("value", "1FQ");


							var dataFieldList = dataFieldNames.ToList();
							Element fields = request.GetElement("fields");
							foreach (string dataFieldName in dataFieldList)
							{
								fields.AppendValue(dataFieldName);
							}

							var key = "requestHistoricalReferenceData " + _count++ + " " + ticker;
							_session.SendRequest(request, new CorrelationID(key));
						}
					}
				}
				catch (Exception)
				{
				}
			}
		}

