		private bool sendIndexDataRequest(string name)
		{
			Debug.WriteLine($"[Portfolio] === sendIndexDataRequest ===");
			Debug.WriteLine($"[Portfolio] Index name: {name}");

			bool ok = false;
			if (name.Length > 0)
			{
				// Query Bloomberg first for live current membership — no manual CSV maintenance needed.
				Debug.WriteLine($"[Portfolio] Trying Bloomberg for index members");
				try
				{
					Service refDataService = _session.GetService("//blp/refdata");
					Request request = refDataService.CreateRequest("ReferenceDataRequest");
					Element securities = request.GetElement("securities");
					Element fields = request.GetElement("fields");

					securities.AppendValue(name + " Index");
					fields.AppendValue("DS325");
					fields.AppendValue("DS192");

					var key = "sendIndexDataRequest " + name;
					_session.SendRequest(request, new CorrelationID(key));
					ok = true;
				}
				catch (Exception ex)
				{
					Debug.WriteLine($"[Portfolio] Bloomberg request failed: {ex.Message}");
				}

				// Fall back to local CSV data if Bloomberg fails or is unavailable.
				if (!ok)
				{
					Debug.WriteLine($"[Portfolio] Falling back to local data for index members");
					ok = loadIndexMembersFromLocal(name);
					//if (ok) Debug.WriteLine($"[Portfolio] Loaded index members from local CSV fallback");
				}
			}
			return ok;
		}
		private bool loadIndexMembersFromLocal(string name)
		{
			bool ok = false;
			try
			{
				// First try _tickerInfos (for SPX and sector indices)
				var tickers = getTickerInfos(name + " Index");

				// If not found in _tickerInfos, try loading from local .txt file
				if (tickers == null || tickers.Count == 0)
				{
					tickers = loadIndexMembersFromFile(name);
				}

				if (tickers != null && tickers.Count > 0)
				{
					//Debug.WriteLine($"[Portfolio] Loaded {tickers.Count} members for {name} from local data");

					lock (_symbols)
					{
						_symbols.Clear();
						foreach (var ticker in tickers)
						{
							Symbol symbol = new Symbol(ticker);
							_symbolChange = true;
							_symbols[ticker] = symbol;
						}
					}
					onPortfolioChanged(new PortfolioEventArgs(PortfolioEventType.Symbol));
					ok = true;
				}
				else
				{
					Debug.WriteLine($"[Portfolio] No local data found for {name}");
				}
			}
			catch (Exception ex)
			{
				Debug.WriteLine($"[Portfolio] Local fallback failed for {name}: {ex.Message}");
			}
			return ok;
		}

		private static List<string> loadIndexMembersFromFile(string indexName)
		{
			var result = new List<string>();

			// Map common index names to filenames
			var fileNames = new List<string>
	{
		indexName + ".txt",
		indexName.Replace(" ", "_") + ".txt",
		indexName + " Index.txt",
		indexName.Replace(" ", "_") + "_Index.txt"
	};

			// Also add common index mappings
			if (indexName.Equals("OEX", StringComparison.OrdinalIgnoreCase) ||
				indexName.Equals("S&P 100", StringComparison.OrdinalIgnoreCase))
			{
				fileNames.Add("OEX.txt");
				fileNames.Add("SP100.txt");
				fileNames.Add("S&P100.txt");
			}
			else if (indexName.Equals("SPX", StringComparison.OrdinalIgnoreCase) ||
					 indexName.Equals("S&P 500", StringComparison.OrdinalIgnoreCase))
			{
				fileNames.Add("SPX.txt");
				fileNames.Add("SP500.txt");
				fileNames.Add("S&P500.txt");
			}

			string localDataPath = @"C:\Users\Public\Documents\ATMML\Bloomberg";

			foreach (var fileName in fileNames)
			{
				var filePath = Path.Combine(localDataPath, fileName);
				if (File.Exists(filePath))
				{
					Debug.WriteLine($"[Portfolio] Found local index file: {filePath}");

					foreach (var line in File.ReadLines(filePath))
					{
						if (string.IsNullOrWhiteSpace(line))
							continue;

						// Skip header lines
						if (line.StartsWith("Ticker", StringComparison.OrdinalIgnoreCase) ||
							line.StartsWith("Symbol", StringComparison.OrdinalIgnoreCase) ||
							line.StartsWith("Date", StringComparison.OrdinalIgnoreCase))
							continue;

						// Handle different formats:
						// Format 1: Just ticker per line
						// Format 2: Ticker,Name,Sector,...
						var parts = line.Split(new[] { ',', '\t' }, StringSplitOptions.RemoveEmptyEntries);
						if (parts.Length > 0)
						{
							var ticker = parts[0].Trim();

							// Add " US Equity" suffix if not present
							if (!ticker.Contains(" "))
							{
								ticker = ticker + " US Equity";
							}

							if (!result.Contains(ticker))
							{
								result.Add(ticker);
							}
						}
					}

					if (result.Count > 0)
					{
						//Debug.WriteLine($"[Portfolio] Loaded {result.Count} tickers from {filePath}");
						break; // Found a valid file, stop searching
					}
				}
			}

			return result;
		}

		private static List<string> getTickerInfos(string indexTicker)
		{
			Debug.WriteLine($"[Portfolio] getTickerInfos called for: {indexTicker}");
			Debug.WriteLine($"[Portfolio] _tickerInfos count: {_tickerInfos?.Count ?? 0}");

			List<string> output = new List<string>();

			if (_tickerInfos == null || _tickerInfos.Count == 0)
			{
				Debug.WriteLine($"[Portfolio] _tickerInfos is empty!");
				return output;
			}

			// For SPX/SP500/OEX, return all current tickers
			if (indexTicker == "SPX Index" || indexTicker == "SP500 Index" ||
				indexTicker == "S&P 500 Index" || indexTicker == "OEX Index" ||
				indexTicker == "OEX V2 Index")
			{
				// Return tickers that are currently active (EndDate >= today)
				var today = DateTime.Today;
				output = _tickerInfos
					.Where(x => x.EndDate >= today)
					.Select(x => x.Ticker)
					.ToList();

				Debug.WriteLine($"[Portfolio] Returning {output.Count} current tickers for {indexTicker}");
			}
			else
			{
				// For sector indices, filter by SectorTicker
				output = _tickerInfos
					.Where(x => x.SectorTicker == indexTicker)
					.Select(x => x.Ticker)
					.ToList();

				Debug.WriteLine($"[Portfolio] Returning {output.Count} sector tickers for {indexTicker}");
			}

			return output;
		}

