		private void processEvent(Event eventObj, Session session)
		{
			try
			{
				switch (eventObj.Type)
				{
					case Event.EventType.RESPONSE:
						processResponseEvent(eventObj, true);
						break;
					case Event.EventType.PARTIAL_RESPONSE:
						processResponseEvent(eventObj, false);
						break;
				}
			}
			catch (System.Exception e)
			{
				string message = e.Message.ToString();
			}
		}

		private void onPortfolioChanged(PortfolioEventArgs e)
		{
			if (PortfolioChanged != null)
			{
				PortfolioChanged(this, e);
			}
		}

		private void processResponseEvent(Event eventObj, bool complete)
		{
			foreach (Message msg in eventObj.GetMessages())
			{
				if (!msg.HasElement(RESPONSE_ERROR))
				{
					if (msg.MessageType.Equals(Bloomberglp.Blpapi.Name.GetName("HistoricalDataResponse")))
					{
						processHistoricalResponse(msg, complete);
					}
					else
					{
						processReferenceResponse(msg, complete);
					}
				}
				else
				{
					var error = msg.GetElement(RESPONSE_ERROR);
					string message = error.GetElementAsString(MESSAGE);
					//Trace.WriteLine("Portfolio error: " + msg.CorrelationID.ToString() + " " + message);
				}
			}
		}

		private void processHistoricalResponse(Message msg, bool complete)
		{

			Dictionary<string, object> referenceData = new Dictionary<string, object>();

			var fieldNames = new List<string>();

			string ticker = string.Empty;
			Boolean hasFieldError = false;
			if (msg.HasElement(RESPONSE_ERROR))
			{
				Element error = msg.GetElement(RESPONSE_ERROR);
				string message = error.GetElementAsString(MESSAGE);

				referenceData["Error"] = message;
				PortfolioEventArgs eventArgs = new PortfolioEventArgs(PortfolioEventType.Error, ticker, referenceData);
				onPortfolioChanged(eventArgs);

				//System.Diagnostics.Debug.WriteLine("Error response: " + message);
			}
			else
			{
				Element secDataArray = msg.GetElement(SECURITY_DATA);
				int numberOfSecurities = secDataArray.NumValues;
				if (secDataArray.HasElement(SECURITY_ERROR))
				{
					Element secError = secDataArray.GetElement(SECURITY_ERROR);
					string message = secError.GetElementAsString(MESSAGE);
				}
				if (secDataArray.HasElement(FIELD_EXCEPTIONS))
				{
					Element error = secDataArray.GetElement(FIELD_EXCEPTIONS);
					for (int errorIndex = 0; errorIndex < error.NumValues; errorIndex++)
					{
						Element errorException = error.GetValueAsElement(errorIndex);
						string field = errorException.GetElementAsString(FIELD_ID);
						Element errorInfo = errorException.GetElement(ERROR_INFO);
						string message = errorInfo.GetElementAsString(MESSAGE);
						hasFieldError = true;

						referenceData[field] = message;
						PortfolioEventArgs eventArgs = new PortfolioEventArgs(PortfolioEventType.Error, ticker, referenceData);
						onPortfolioChanged(eventArgs);

						//System.Diagnostics.Debug.WriteLine("Field exception: " + "field name = " + field + " Message = " + message);
					}
				}


				//System.Diagnostics.Debug.WriteLine("Number of securities = " + numberOfSecurities.ToString());
				for (int index = 0; index < numberOfSecurities; index++)
				{
					foreach (Element secData in secDataArray.Elements)
					{
						var name = secData.Name.ToString();
						switch (name)
						{
							case "eidsData":
								break;
							case "security":
								ticker = modifyExchangeCode(secData.GetValueAsString());
								break;
							case "fieldData":
								if (!hasFieldError && secData.NumValues > 0)
								{
									//System.Diagnostics.Debug.WriteLine("Data: " + ticker + " " + secData.NumValues);
									for (int pointIndex = 0; pointIndex < secData.NumValues; pointIndex++)
									{
										Element field = secData.GetValueAsElement(pointIndex);

										//System.Diagnostics.Debug.WriteLine("      " + pointIndex.ToString() + " : "  + field.ToString());

										if (field.HasElement("date"))
										{
											Element item = field.GetElement("date");
											DateTime barTime = item.GetValueAsTime().ToSystemDateTime();

											int elementCount = field.NumElements;
											for (int elementIndex = 1; elementIndex < elementCount; elementIndex++)
											{
												Element data = field.GetElement(elementIndex);
												double value = data.GetValueAsFloat64();
												string date = barTime.ToString("yyyy-MM-dd");
												string key = data.Name + ":" + date;

												string fieldName = data.Name.ToString();

												fieldNames.Add(fieldName);

												if (fieldName == "ANNOUNCEMENT_DT" || fieldName == "DS957")
												{
													int year = barTime.Year;
													int quarter = barTime.Month / 3;
													string reportKey = ticker + ":" + year + "Q" + quarter;
													string reportDate = data.GetValueAsString();
													_reportDates[reportKey] = reportDate;
												}

												else if (fieldName == "CUR_MKT_CAP")
												{
													value *= 1000000;
												}

												referenceData[key] = value;
											}
										}
										else
										{
											//System.Diagnostics.Debug.WriteLine("No date: " + ticker);
										}
									}
								}
								else
								{
									//System.Diagnostics.Debug.WriteLine("No data: " + ticker);
								}
								break;
						}
					}

					if (ticker.Length > 0)
					{
						referenceData = fixReportDates(ticker, referenceData);

						saveData(ticker, referenceData);

						fieldNames = fieldNames.Distinct().ToList();
						foreach (var fieldName in fieldNames)
						{
							var data = loadData(ticker, fieldName);
							foreach (var kvp in data)
							{
								referenceData[fieldName + ":" + kvp.Key] = kvp.Value;
							}
						}

						// notification after processing historical response
						PortfolioEventArgs eventArgs = new PortfolioEventArgs(PortfolioEventType.ReferenceData, ticker, referenceData, 2);
						onPortfolioChanged(eventArgs);
					}
				}
			}
		}

		private Dictionary<string, object> fixReportDates(string ticker, Dictionary<string, object> input)
		{
			Dictionary<string, object> output = new Dictionary<string, object>();

			List<string> fieldNames = new List<string>();
			foreach (var key in input.Keys)
			{
				string[] fields = key.Split(':');
				string fieldName = fields[0];
				fieldNames.Add(fieldName);
			}
			fieldNames = fieldNames.Distinct().ToList();

			foreach (var fieldName in fieldNames)
			{
				if (fieldName == "ANNOUNCEMENT_DT")
				{
					foreach (var key in input.Keys)
					{
						string[] fields = key.Split(':');
						if (fields[0] == fieldName)
						{
							output[key] = input[key];
						}
					}
				}
				else
				{
					bool convertDates = true;

					List<DateTime> dates = new List<DateTime>();
					foreach (var key in input.Keys)
					{
						string[] fields = key.Split(':');
						if (fields.Length >= 2)
						{
							if (fields[0] == fieldName)
							{
								try
								{
									DateTime date = DateTime.ParseExact(fields[1], "yyyy-MM-dd", null);
									dates.Add(date);
								}
								catch (Exception x)
								{
								}
							}
						}
					}

					dates.Sort();

					TimeSpan minTimeSpan = new TimeSpan(45, 0, 0, 0);  // 45 days
					DateTime previousDate = new DateTime();
					foreach (var date in dates)
					{
						if (previousDate != default(DateTime) && date - previousDate < minTimeSpan)
						{
							convertDates = false;
							break;
						}
						previousDate = date;
					}

					foreach (var kvp1 in input)
					{
						string[] fields = kvp1.Key.Split(':');
						if (fields.Length >= 2)
						{
							if (fields[0] == fieldName)
							{
								var date = DateTime.ParseExact(fields[1], "yyyy-MM-dd", null);
								if (convertDates)
								{
									bool found = false;
									TimeSpan minTS = new TimeSpan(45, 0, 0, 0);
									foreach (var kvp2 in _reportDates)
									{
										var key = kvp2.Key;
										if (key.Contains(ticker))
										{
											var dateText = kvp2.Value as string;
											DateTime reportDate;
											if (DateTime.TryParseExact(dateText, "yyyyMMdd", null, System.Globalization.DateTimeStyles.None, out reportDate))
											{
												if (reportDate >= date)
												{
													TimeSpan ts = reportDate - date;
													if (ts.TotalDays < minTS.TotalDays)
													{
														minTS = ts;
														date = reportDate;
														found = true;
													}
												}
											}
										}
									}

									if (!found)
									{
										date += minTS;  // assuming the date associate with the fundamental is an end-of-quarter date
									}
								}

								var outputKey = fieldName + ":" + date.ToString("yyyy-MM-dd");
								output[outputKey] = kvp1.Value;
							}
						}
					}
				}
			}
			return output;
		}

		private void processReferenceResponse(Message msg, bool complete)
		{
			if (msg.HasElement(SECURITY_DATA))
			{
				Element securities = msg.GetElement(SECURITY_DATA);
				int numSecurities = securities.NumValues;
				for (int secCnt = 0; secCnt < numSecurities; ++secCnt)
				{
					Element security = securities.GetValueAsElement(secCnt);
					string ticker = security.GetElementAsString(SECURITY);

					Dictionary<string, object> referenceData = new Dictionary<string, object>();
					Dictionary<string, object> historicalReferenceData = new Dictionary<string, object>();

					if (!security.HasElement("securityError"))
					{
						Element fields = security.GetElement(FIELD_DATA);
						if (fields.NumElements > 0)
						{

							var sendBetaEvent = false;

							int numElements = fields.NumElements;
							for (int eleCtr = 0; eleCtr < numElements; ++eleCtr)
							{
								Element field = fields.GetElement(eleCtr);
								// Checking if the field is Bulk field
								if (field.Datatype == Bloomberglp.Blpapi.Schema.Datatype.SEQUENCE)
								{
									processBulkField(ticker, field, referenceData, historicalReferenceData);
								}
								else
								{
									processRefField(ticker, msg.CorrelationID, field, referenceData, out sendBetaEvent);
								}
							}

							if (sendBetaEvent)
							{
								PortfolioEventArgs eventArgs1 = new PortfolioEventArgs(PortfolioEventType.Beta, ticker, referenceData, 3);
								onPortfolioChanged(eventArgs1);
							}
						}

						Element fieldExceptions = security.GetElement(FIELD_EXCEPTIONS);
						if (fieldExceptions.NumValues > 0)
						{
							for (int k = 0; k < fieldExceptions.NumValues; ++k)
							{
								Element fieldException = fieldExceptions.GetValueAsElement(k);
								string fieldName = fieldException.GetElementAsString("fieldId");
								referenceData[fieldName] = "";
							}
						}


						// notification after processing reference response
						PortfolioEventArgs eventArgs = new PortfolioEventArgs(PortfolioEventType.ReferenceData, ticker, referenceData, 3);
						onPortfolioChanged(eventArgs);

						saveData(ticker, historicalReferenceData);

					}
					else
					{
						//System.Diagnostics.Debug.WriteLine("Portfolio security error:"   + ticker);
					}
				}
			}

			if (msg.HasElement(DATA))
			{
				Element data = msg.GetElement(DATA);
				Element securities = data.GetElement(SECURITY_DATA);
				int numSecurities = securities.NumValues;
				for (int i = 0; i < numSecurities; ++i)
				{
					string ticker = "";
					string description = "";

					Element security = securities.GetValueAsElement(i);
					ticker = security.GetElementAsString(SECURITY);


					if (!security.HasElement("securityError"))
					{
						Element fields = security.GetElement(FIELD_DATA);
						if (fields.NumElements > 0)
						{
							int numElements = fields.NumElements;
							for (int j = 0; j < numElements; ++j)
							{
								Element field = fields.GetElement(j);

								string name = field.Name.ToString();
								string value = field.GetValueAsString();

								if (name == "Ticker")
								{
									ticker = modifyExchangeCode(value);
									for (int ii = 0; ii < 10; ii++) ticker = ticker.Replace("  ", " ");
									ticker += " Equity";
								}
								else if (name == "Security")
								{
									description = value;
									for (int ii = 0; ii < 10; ii++) description = description.Replace("  ", " ");
								}

							}
						}
						Element fieldExceptions = security.GetElement(FIELD_EXCEPTIONS);
						if (fieldExceptions.NumValues > 0)
						{
							for (int k = 0; k < fieldExceptions.NumValues; ++k)
							{
								Element fieldException =
									fieldExceptions.GetValueAsElement(k);
							}
						}

						if (ticker.Length > 0)
						{
							Symbol symbol = new Symbol(ticker);
							if (description.Length > 0)
							{
								symbol.Description = description;
							}

							lock (_symbols)
							{
								if (!_symbols.ContainsKey(ticker))
								{
									_symbolChange = true;
								}
								_symbols[ticker] = symbol;
							}
						}
					}
					else
					{
						//System.Diagnostics.Debug.WriteLine("Portfolio security error:" + ticker);
					}
				}
			}

			if (complete)
			{
				onPortfolioChanged(new PortfolioEventArgs(_symbolChange ? PortfolioEventType.Symbol : PortfolioEventType.Description));
				if (_requestExtraInfo)
				{
					_requestExtraInfo = false;
					requestSymbolInfo(true);
				}
			}

			else
			{

			}
		}

		private void processBulkField(string ticker, Element refBulkField, Dictionary<string, object> referenceData, Dictionary<string, object> historicalReferenceData)
		{
			string fieldName = refBulkField.Name.ToString();
			// Get the total number of Bulk data points
			int numofBulkValues = refBulkField.NumValues;
			List<DateTime> _historicalEarnings = new List<DateTime>();

			List<PRTUTrade> trades = new List<PRTUTrade>();
			PRTUTrade trade = null;

			bool yieldData = false;
			for (int bvCtr = 0; bvCtr < numofBulkValues; bvCtr++)
			{
				Element bulkElement = refBulkField.GetValueAsElement(bvCtr);
				// Get the number of sub fields for each bulk data element
				int numofBulkElements = bulkElement.NumElements;

				string exDate = "";
				string payableDate = "";

				// Read each field in Bulk data
				double tenor = 0;
				string tenorTicker = "";
				for (int beCtr = 0; beCtr < numofBulkElements; beCtr++)
				{
					Element elem = bulkElement.GetElement(beCtr);
					string name = elem.Name.ToString();
					string value = elem.GetValueAsString();

					if (fieldName == "INDX_MOST_UP")
					{
						if (bvCtr == 0)
						{
							if (name == "Member Name")
							{
								referenceData["INDX_MOST_UP"] = value;
							}
							else if (name == "Percentage Change")
							{
								referenceData["INDX_MOST_UP_PC"] = value;
							}
						}
					}
					else if (fieldName == "INDX_MOST_DOWN")
					{
						if (bvCtr == 0)
						{
							if (name == "Member Name")
							{
								referenceData["INDX_MOST_DOWN"] = value;
							}
							else if (name == "Percentage Change")
							{
								referenceData["INDX_MOST_DOWN_PC"] = value;
							}
						}
					}
					else if (fieldName == "PORTFOLIO_DATA")  // member
					{
						if (trade == null) trade = new PRTUTrade();
						if (name == "Security") trade.Symbol = value;
						else if (name == "Position") trade.Position = value;
						else if (name == "Market Value") trade.MarketValue = value;
						else if (name == "Cost Date") trade.EntryDate = value;
					}

					else if (fieldName == "PORTFOLIO_MEMBERS")  // member
					{
						ticker = modifyExchangeCode(value);
						Symbol symbol = new Symbol(ticker);
						lock (_symbols)
						{
							_symbolChange = true;
							_symbols[ticker] = symbol;
						}
					}
					else if (fieldName == "DS325")  // member
					{
						ticker = modifyExchangeCode((value.Contains(" Index") || value.Contains("Curncy")) ? value : value + " Equity");
						Symbol symbol = new Symbol(ticker);
						lock (_symbols)
						{
							_symbolChange = true;
							_symbols[ticker] = symbol;
						}
					}
					else if (fieldName == "DY785")  // peers
					{
						ticker = modifyExchangeCode(value + " Equity");
						Symbol symbol = new Symbol(ticker);
						lock (_symbols)
						{
							_symbolChange = true;
							_symbols[ticker] = symbol;
						}
					}
					else if (fieldName == "DV156")  // historical dividend
					{
						lock (_symbols)
						{
							if (name == "Ex-Date")
							{
								exDate = value;
							}
							else if (name == "Payable Date")
							{
								payableDate = value;
							}
							else if (name == "Dividend Amount")
							{
								double dividend = double.Parse(value);
								if (exDate != "" && payableDate != "" && dividend > 0)
								{
									string key = exDate + ":" + payableDate;
									lock (_symbols)
									{
										if (_symbols.ContainsKey(ticker))
										{
											_symbols[ticker].Dividends[key] = dividend;
										}
									}
									historicalReferenceData["DV156:" + key] = dividend;
								}
							}
						}
					}
					else if (fieldName == "DV031")  // historical split
					{
						lock (_symbols)
						{
							if (_symbols.ContainsKey(ticker))
							{
								//_symbols[ticker].Splits[date] = value;
							}
						}
					}
					else if (fieldName == "EARN_ANN_DT_TIME_HIST_WITH_EPS" && name == "Announcement Date")
					{
						DateTime dateTime = elem.GetValueAsTime().ToSystemDateTime();
						_historicalEarnings.Add(dateTime);

					}

					else if (fieldName == "CURVE_TENOR_RATES")
					{
						yieldData = true;

						if (!_yields.ContainsKey(ticker))
						{
							_yields[ticker] = new List<Yield>();
						}

						if (name == "Tenor")
						{
							var monthText = Regex.Match(value, @"\d+M").Value.Replace("M", "");
							var yearText = Regex.Match(value, @"\d+").Value;
							tenor = (monthText.Length > 0) ? int.Parse(monthText) / 12.0 : int.Parse(yearText);
						}
						if (name == "Tenor Ticker")
						{
							tenorTicker = modifyExchangeCode(value);
						}
						if (name == "Mid Yield")
						{
							double result;
							if (double.TryParse(value, out result))
							{
								_yields[ticker].Add(new Yield(tenorTicker, "", tenor, result, 0));
							}
						}
					}
					else
					{
						string elementName = name;
						string elementValue = value;
						//System.Diagnostics.Debug.WriteLine("REF BULK FIELD " + elementName + " " + elementValue);
					}
				}

				if (trade != null)
				{
					trades.Add(trade);
					trade = null;
				}
			}

			if (yieldData)
			{
				PortfolioEventArgs eventArgs = new PortfolioEventArgs(PortfolioEventType.Yield, ticker, referenceData);
				onPortfolioChanged(eventArgs);
			}

			if (_historicalEarnings.Count > 0)
			{
				referenceData["EARN_ANN_DT_TIME_HIST_WITH_EPS"] = _historicalEarnings;
			}

			if (trades.Count > 0)
			{
				Trade.Manager.LoadPRTUTrades(ticker, trades);

				foreach (var trade1 in trades)
				{
					var ticker1 = trade1.Symbol;
					_symbols[ticker1] = new Symbol(ticker1);
				}

				PortfolioEventArgs eventArgs = new PortfolioEventArgs(PortfolioEventType.Symbol, ticker, referenceData);
				onPortfolioChanged(eventArgs);
			}
		}



