			//    referenceData[fieldName] = value;
			//
			else if (fieldName == "EXPECTED_REPORT_DT" || fieldName == "BDVD_NEXT_EST_DECL_DT" || fieldName == "BDVD_NEXT_EST_EX_DT" || fieldName == "BDVD_NEXT_EST_PAY_DT")
			{
				DateTime value = field.GetValueAsTime().ToSystemDateTime();
				referenceData[fieldName] = value;

			}
			else if (fieldName == "REL_5D" || fieldName == "REL_1M" || fieldName == "REL_6M")
			{
				double value = field.GetValueAsFloat64();
				referenceData[fieldName] = value;
			}
			else if (fieldName == "REL_INDEX")
			{
				string symbol = field.GetValue() as string;
				referenceData[fieldName] = symbol;
				saveValue(ticker, fieldName, symbol);
			}
			else if (fieldName == "GICS_INDUSTRY_GROUP_NAME")
			{
				string value = field.GetValueAsString();
				referenceData[fieldName] = value;
				saveValue(ticker, fieldName, value);
			}
			else
			{ // assume a double
				try
				{
					double value = field.GetValueAsFloat64();
					referenceData[fieldName] = value;
				}
				catch (Exception x)
				{

				}
			}

			foreach (var kvp in referenceData)
			{
				var name = kvp.Key;
				var value = kvp.Value;
				if (value is string)
				{
					var fileName = getFileName(ticker, name, false);

					if (fileName.Length > 0)
					{
						MainView.SaveUserData(fileName, value as string, true);
						MainView.SaveUserData(fileName.Replace(".csv", "") + @"_Time", DateTime.Now.ToString("yyyyMMddHHmmss"));
					}
				}
			}
		}

		void saveValue(string ticker, string fieldName, string value)
		{
			var fileName = getFileName(ticker, fieldName, false);

			if (fileName.Length > 0)
			{
				MainView.SaveUserData(fileName, value, true);
				MainView.SaveUserData(fileName.Replace(".csv", "") + @"_Time", DateTime.Now.ToString("yyyyMMddHHmmss"));
			}
		}

