		private string getFileName(string symbol, string name, bool history)
		{
			string output = "";

			try
			{
				symbol = symbol.Replace("/", "-").Replace("*", "#");
				output = @"Bloomberg\" + symbol + @"\" + name + (history ? "_All" : "_Current") + ".csv";
			}
			catch (Exception e)
			{
				Console.WriteLine(e.Message);
			}

			return output;
		}

		private void saveData(string symbol, Dictionary<string, object> input)
		{
			try
			{
				var data = new Dictionary<string, Dictionary<string, string>>();
				foreach (var kvp in input)
				{
					string key = kvp.Key;
					string value = ((double)kvp.Value).ToString("R");

					string[] fields = key.Split(':');
					if (fields.Length >= 2)
					{
						string fieldName = fields[0];
						string dataKey = fields.Length >= 3 ? fields[1] + ":" + fields[2] : fields[1];

						Dictionary<string, string> fieldData = null;
						if (!data.TryGetValue(fieldName, out fieldData))
						{
							fieldData = loadData(symbol, fieldName);
							data[fieldName] = fieldData;
						}

						fieldData[dataKey] = value;
					}
				}

				foreach (var kvp in data)
				{
					string name = kvp.Key;
					var fieldData = kvp.Value;

					//Trace.WriteLine("SAVE " + name + " for " + symbol + " count = " + fieldData.Count);

					saveData(symbol, name, fieldData);
				}
			}
			catch (Exception e)
			{
				Console.WriteLine(e.Message);
			}
		}


		private void saveData(string symbol, string name, Dictionary<string, string> data)
		{
			string fileName = getFileName(symbol, name, true);

			//Trace.WriteLine("Save " + name + " for " + symbol + " count = " + data.Count);

			if (fileName.Length > 0)
			{
				var sb = new StringBuilder();
				List<string> keys = data.Keys.ToList();
				keys.Sort();
				foreach (var key in keys)
				{
					sb.Append(key + "\u0001" + data[key] + "\n");
				}
				MainView.SaveUserData(fileName, sb.ToString(), true);
				MainView.SaveUserData(fileName.Replace(".csv", "") + @"_Time", DateTime.Now.ToString("yyyyMMddHHmmss"));

				_refCache[fileName] = data;
			}
		}

		private static Dictionary<string, Dictionary<string, string>> _refCache = new Dictionary<string, Dictionary<string, string>>();

		public Dictionary<string, string> loadData(string symbol, string name, bool history = true)
		{
			var output = new Dictionary<string, string>();

			string fileName = getFileName(symbol, name, history);

			Dictionary<string, string> cacheData;
			if (_refCache.TryGetValue(fileName, out cacheData))
			{
				output = cacheData;
			}

			else if (fileName.Length > 0)
			{
				var data1 = MainView.LoadUserData(fileName, true);
				if (data1.Length > 0)
				{
					var lines = data1.Split('\n');
					for (var index = 0; index < lines.Length; index++)
					{
						var line = lines[index];
						string[] fields = line.Split('\u0001');
						if (!history && fields.Length == 1)
						{
							output["Value" + (index + 1)] = fields[0];
						}
						else if (fields.Length >= 2)
						{
							output[fields[0]] = fields[1];
						}
					}
				}
			}
			return output;
		}


		private DateTime getStartDate(string symbol, string name)
		{
			var aodName = getAODFieldNames().Contains(name);

			//DateTime output = DateTime.Now - new TimeSpan((aodName ? 1 : 20) * 365, 0, 0, 0);
			DateTime output = DateTime.Now - new TimeSpan(5 * 365, 0, 0, 0);

			var data = loadData(symbol, name).Keys.ToList();
			data.Sort();
			if (data.Count >= 4)
			{
				string item = data[data.Count - 4];
				string[] fields = item.Split(':');
				string date = fields[0];
				output = DateTime.Parse(date);
				output = new DateTime(output.Year, output.Month, output.Day);
			}

			return output;
		}


